parameters.functionCode:
const alert = items[0].json;
const enriched = alert.enriched || {};
const level = enriched.level || 0;

// Determine severity
let severity = 'low';
if (level >= 12) severity = 'critical';
else if (level >= 7) severity = 'high';
else if (level >= 4) severity = 'medium';

// Extract IOCs
const iocs = {
  ips: [],
  domains: [],
  hashes: [],
  urls: []
};

const fullLog = alert.alert?.full_log || '';
const srcIp = enriched.source_ip;
const dstIp = enriched.destination_ip;

if (srcIp && srcIp !== 'unknown') iocs.ips.push(srcIp);
if (dstIp && dstIp !== 'unknown') iocs.ips.push(dstIp);

// Extract IPs from log
const ipRegex = /\b(?:\d{1,3}\.){3}\d{1,3}\b/g;
const ips = fullLog.match(ipRegex) || [];
ips.forEach(ip => { if (!iocs.ips.includes(ip)) iocs.ips.push(ip); });

// Extract domains
const domainRegex = /\b[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}\b/g;
const domains = fullLog.match(domainRegex) || [];
domains.forEach(d => { if (!iocs.domains.includes(d)) iocs.domains.push(d); });

// Extract hashes (MD5, SHA1, SHA256)
const hashRegex = /\b[a-fA-F0-9]{32,64}\b/g;
const hashes = fullLog.match(hashRegex) || [];
hashes.forEach(h => { if (!iocs.hashes.includes(h)) iocs.hashes.push(h); });

return [{
  json: {
    ...alert,
    enriched: {
      ...enriched,
      severity,
      iocs
    }
  }
}];

const alert = items[0].json;
const openclaw = items[1]?.json || {};
const misp = items[2]?.json || {};

// Build ticket description
let description = `**Wazuh Alert - ${alert.enriched.severity.toUpperCase()}**

`;
description += `**Rule:** ${alert.enriched.rule_description} (ID: ${alert.enriched.rule_id})
`;
description += `**Level:** ${alert.enriched.level}
`;
description += `**Agent:** ${alert.enriched.agent_name} (${alert.enriched.agent_ip})
`;
description += `**Source IP:** ${alert.enriched.source_ip}
`;
description += `**Destination IP:** ${alert.enriched.destination_ip}
`;
description += `**Time:** ${alert.enriched.timestamp}

`;

if (Object.keys(alert.enriched.iocs).some(k => alert.enriched.iocs[k].length > 0)) {
  description += `**IOCs:**
`;
  if (alert.enriched.iocs.ips.length) description += `- IPs: ${alert.enriched.iocs.ips.join(', ')}
`;
  if (alert.enriched.iocs.domains.length) description += `- Domains: ${alert.enriched.iocs.domains.join(', ')}
`;
  if (alert.enriched.iocs.hashes.length) description += `- Hashes: ${alert.enriched.iocs.hashes.join(', ')}
`;
  description += `
`;
}

if (openclaw.analysis) {
  description += `**AI Analysis:**
${openclaw.analysis}

`;
  description += `**Recommendation:** ${openclaw.recommendation}

`;
}

if (misp.response?.Attribute?.length) {
  description += `**MISP Matches:**
`;
  misp.response.Attribute.slice(0, 5).forEach(attr => {
    description += `- ${attr.type}: ${attr.value} (${attr.category}) - ${attr.Tag?.map(t => t.name).join(', ') || 'no tags'}
`;
  });
  description += `
`;
}

description += `**Raw Log:**
\`\`\`
${alert.alert.full_log}
\`\`\`
`;

return [{
  json: {
    ...alert,
    ticket: {
      title: `[${alert.enriched.severity.toUpperCase()}] ${alert.enriched.rule_description}`,
      description,
      priority: alert.enriched.severity === 'critical' ? '1' : alert.enriched.severity === 'high' ? '2' : '3',
      tags: ['wazuh', 'security', alert.enriched.severity, `rule-${alert.enriched.rule_id}`]
    }
  }
}];

