const alert = items[0].json;

// Log for audit
console.log(`[SOAR] Processed alert: ${alert.enriched.rule_id} - ${alert.enriched.severity} - ${alert.enriched.source_ip}`);

return [{
  json: {
    status: 'completed',
    alert_id: alert.enriched.rule_id,
    severity: alert.enriched.severity,
    source_ip: alert.enriched.source_ip,
    ticket_created: !!items[1]?.json?.id,
    blocked: alert.enriched.severity === 'critical',
    timestamp: new Date().toISOString()
  }
}];
